module top_module( newSP , SP, CE, PRESET, CLK);input [15:0] newSP;
    input CE;
    input PRESET;
    input CLK;
    output reg [15:0] SP;

	 always @(posedge CLK ) begin
		if (PRESET == 1) 
			SP <= 16'hf3ff;
		else if (CE == 1)
			SP <= newSP;
	 end


  always @(*) begin
    if (1'b0) begin
      SP <= 16'h0000;
    end
  end

endmodule
